    var LANG_STORAGE_KEY = "ft_lang";
    var savedLang = null;
    try {
        savedLang = localStorage.getItem(LANG_STORAGE_KEY);
    } catch (error) {
        savedLang = null;
    }
    var currentLang = savedLang === "ar" ? "ar" : "en";
    var langToggles = document.querySelectorAll(".lang-toggle, #langToggle");
    var html = document.documentElement;

    function applyLanguage(lang) {
        var dict = translations[lang];
        html.setAttribute("lang", lang);
        html.setAttribute("dir", lang === "ar" ? "rtl" : "ltr");
        langToggles.forEach(function (btn) {
            btn.textContent = lang === "en" ? "AR" : "EN";
        });

        document.querySelectorAll("[data-i18n]").forEach(function (el) {
            var key = el.getAttribute("data-i18n");
            if (dict[key]) {
                el.textContent = dict[key];
            }
        });

        document.querySelectorAll("[data-i18n-placeholder]").forEach(function (el) {
            var key = el.getAttribute("data-i18n-placeholder");
            if (dict[key]) {
                el.setAttribute("placeholder", dict[key]);
            }
        });
    }

    langToggles.forEach(function (btn) {
        btn.addEventListener("click", function () {
            currentLang = currentLang === "en" ? "ar" : "en";
            try {
                localStorage.setItem(LANG_STORAGE_KEY, currentLang);
            } catch (error) {
                // No-op if storage is blocked.
            }
            applyLanguage(currentLang);
        });
    });

    applyLanguage(currentLang);

    // Expose for other scripts that need translations
    window.FT = { translations: translations, getLang: function () { return currentLang; } };
